import{_ as t,o as a,c as n,a0 as s}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Create an Event Instance","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/create-instance.md","filePath":"how-to/create-instance.md"}'),o={name:"how-to/create-instance.md"};function l(i,e,r,h,c,d){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="create-an-event-instance" tabindex="-1">Create an Event Instance <a class="header-anchor" href="#create-an-event-instance" aria-label="Permalink to &quot;Create an Event Instance&quot;">​</a></h1><p>Create an event instance when you want a real dated run of a template that can hold manual rows, screenshot imports, analytics, and rewards.</p><blockquote><p>Screenshot placeholder: instances-list.png</p></blockquote><h2 id="what-you-choose-when-creating-one" tabindex="-1">What you choose when creating one <a class="header-anchor" href="#what-you-choose-when-creating-one" aria-label="Permalink to &quot;What you choose when creating one&quot;">​</a></h2><p>The <strong>Add Event Instance</strong> form lets you set:</p><ul><li>the event template</li><li>an optional instance name</li><li>start and end dates</li><li>stage count and current stage, if the event uses stages</li><li>stage dates, if the event uses stages</li><li>whether total points stack across stages for staged events</li></ul><h2 id="basic-workflow" tabindex="-1">Basic workflow <a class="header-anchor" href="#basic-workflow" aria-label="Permalink to &quot;Basic workflow&quot;">​</a></h2><ol><li>Open <strong>Event Instances</strong>.</li><li>Choose the template.</li><li>Set the date range.</li><li>If the event uses stages, confirm the stage count and dates.</li><li>Select <strong>Create instance</strong>.</li></ol><p>After saving, the app opens the new instance.</p><h2 id="how-different-event-types-behave" tabindex="-1">How different event types behave <a class="header-anchor" href="#how-different-event-types-behave" aria-label="Permalink to &quot;How different event types behave&quot;">​</a></h2><ul><li><strong>Single-session</strong> events usually use one start date and one end date.</li><li><strong>Multi-day cumulative</strong> events use a window, then store dated snapshots inside that window.</li><li><strong>Multi-stage</strong> events let you define stages and stage dates up front.</li></ul><h2 id="helpful-hints-from-the-page" tabindex="-1">Helpful hints from the page <a class="header-anchor" href="#helpful-hints-from-the-page" aria-label="Permalink to &quot;Helpful hints from the page&quot;">​</a></h2><p>The create page also shows:</p><ul><li>a quick explanation of the selected event mode</li><li>recent previous dates for the same template</li><li>a stage timeline preview for staged events</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../events/templates-overview.html">Event Templates &amp; Instances Explained</a></li><li><a href="./instance-detail.html">Work Inside an Instance</a></li><li><a href="./kvk-prep.html">Run a KvK Prep Session</a></li></ul>',16)])])}const f=t(o,[["render",l]]);export{u as __pageData,f as default};
